import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "14:05。回家途中。", background: Background.Chapter_10_Ch10_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有直接回家。她走得很慢。不是因為累。是因為在想。16:30。清澄區民中心。藍色傘。她還沒決定去不去。", background: Background.Chapter_10_Ch10_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先確認。低風險確認。不搜敏感詞。不登入工作帳號。只看公開頁。只看已經找到的東西。", background: Background.Chapter_10_Ch10_Act6_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在路上找了一家咖啡店。不是連鎖的。很小的。角落有一張桌子。插座在牆上。她點了一杯最便宜的。坐下來。打開手機。不是掌機。是手機。用行動數據。不連店裡的網路。", background: Background.Chapter_10_Ch10_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯水瀨葵的尋人頁。再看一次。這次不是看內容。是看結構。看更新頻率。看留言。看轉發。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她打開那個簡陋的頁面。白底。黑字。失蹤第 41 日。她往下捲。這次她看得更仔細。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "頁面有日期。每一則更新都有日期。她用手指一個一個數。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一則。四十一日前。失蹤當天。第二則。三十八日前。第三則。三十五日前。每隔幾天一則。規律。像心跳。像一個人定了鬧鐘。每隔幾天起床。打開電腦。更新頁面。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看早期的貼文。字比較多。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四十一日前。第一則。字很長。她掃了一遍。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯「謝謝大家幫忙轉發。如果有任何消息請聯絡。葵那天放學後參加學校合作的睡眠健康檢查，晚間沒有回家。她不會自己離開的。她連去便利店都會跟我說。請幫忙。」", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那段字。一個母親。失蹤當天。寫的。字很完整。有禮貌。有細節。有請求。像還相信有人會幫忙。像還相信頁面更新了就會有人看見。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她還在說謝謝。失蹤第一天。她還在說謝謝大家幫忙轉發。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往下捲。三十八日前。字少了一點。但還是完整的。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯「謝謝分享的人。今天還沒有消息。警方說還在確認。」", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三十五日前。更少。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯「今天沒有消息。謝謝。」", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三十日前。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯「今天也沒有消息。」", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往下捲。越往下。字越少。像一條線。從完整句子。變成短句。變成一行。變成五個字。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯謝謝大家幫忙轉發。謝謝分享的人。今天還沒有消息。今天沒有消息。今天也沒有消息。也沒有。也沒有。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停在最近一則。兩日前。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五個字。沒有標點。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "今天也沒有消息", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯四十一日。從「謝謝大家幫忙轉發」到「今天也沒有消息」。從一整段話到五個字。像一個人慢慢被掏空。不是不願意寫。是沒有東西可以寫了。每天都一樣。沒有消息。沒有消息。沒有消息。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往下看。留言區。頁面有留言功能。很基本。不是社群平台。是家屬自己架的。但有人留言。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點開留言。一條一條看。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯早期留言。大部分是轉發支持。「加油」「祈禱平安」「幫忙轉發了」。普通的。善意的。像任何一個尋人頁面會收到的。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她繼續往下。中間開始出現不同的聲音。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一則留言。二十日前。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "孩子青春期離家不要怪社會，自己怎麼教的？", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。手指在螢幕上停住。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯你不知道。你什麼都不知道。你不知道她討厭游泳。你不知道她收集冰棒棍。你不知道她失蹤前說了明天檢查不想睡。你不知道她的最後訊息不像她。你什麼都不知道。你就坐在螢幕後面打一行字。青春期離家。不要怪社會。自己怎麼教的。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往下看。那則留言下面。有回覆。是水瀨葵的母親回的。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她回了。她回覆了那則留言。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "回覆很短。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "她不是那樣的孩子。謝謝您的關心。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她不是那樣的孩子。謝謝您的關心。有人在留言裡罵她。她還是回了。還是說謝謝。像被打了還要跟對方說謝謝您的手。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她繼續往下。另一則留言。十五日前。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "這種年紀的小孩說走就走，過幾天自己會回來啦", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下面也有回覆。同樣的人。同樣的語氣。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "她不會自己走。她連去便利店都會跟我說。謝謝。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她連去便利店都會跟我說。這句話她在第一則更新裡也寫過。四十一日前寫過一次。十五日前又寫了一次。像在反覆證明一件事。我的孩子不會自己走。她連去便利店都會跟我說。她不會。她不會。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把每一則惡意留言都看了。每一則下面都有回覆。每一則。一條一條。那個母親回覆了每一條留言。不管是支持的還是攻擊的。不管是善意的還是惡意的。她都回了。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她為什麼要回每一條。因為她怕。她怕如果有一條沒回。那條就會變成最後一條。頁面就會停在那裡。停在一個陌生人罵她的話上面。她不能讓那個變成最後一句。她要自己控制最後一句。所以她回每一條。每一條都回。都說謝謝。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她靠在椅背上。咖啡涼了。她沒有喝。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯悠真。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想起悠真的房間。桌上那包未拆的零食。洋芋片。他失蹤前一天買的。放在桌上。沒有拆。包裝上的日期還是有效的。還可以吃。但沒有人會去拆它。因為那是他買的。那是他要吃的。等他回來拆。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯水瀨葵的鐵盒。冰棒棍。日期。悠真的洋芋片。未拆。都是一樣的東西。都是一個孩子留下的。都是一個家人在等的。不是線索。不是證據。是等待。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我以為我和水瀨家共享的是線索。黑色海。倒月。睡眠檢查。最後訊息不像本人。警方初期當自願離家。這些是線索。這些是模式。這些是可以比對的東西。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但不是。不只是線索。我們共享的是等待。每天早上醒來。看手機。沒有訊息。每天晚上睡前。看門口。沒有動靜。每天。每天。每天。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把視線移回螢幕。頁面上有一張照片。不是黑色海。不是遊戲截圖。是一張普通的生活照。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨葵站在便利店門口。手裡拿著一根冰棒。在笑。很普通的笑。像任何一個十四歲的女孩子。買了冰棒。站在便利店門口。曬著太陽。笑。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯那張照片和黑色海完全無關。她拿著冰棒。在笑。她不知道自己四十一日後會變成一個帳號。一張黑海圖。一行「明天檢查，不想睡」。一個越來越短的母親的更新。一個越來越大的數字。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那張照片。看了很久。咖啡店裡有人在說話。有人在結帳。有人在拉椅子。她都沒聽見。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯比對。做完了情緒的部分。做資料的部分。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她打開手機備忘錄。新建一個頁面。不標題。不存名字。只打字。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真。水瀨葵。比對。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她開始打。手指在螢幕上敲。很慢。有幾個字打錯了。她刪掉重打。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一項。年齡。悠真十五歲。水瀨葵十四歲。都未成年。都是中學生。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她打下去。錯了一個字。把十四打成十四。沒錯。繼續。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第二項。睡眠檢查。悠真參加學校合作睡眠健康檢查。水瀨葵也參加學校合作睡眠健康檢查。同一個詞。同一個流程。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她打下去。第三項。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第三項。最後訊息。悠真的簡訊不像他。水瀨葵的最後訊息也不像她。兩個都被家屬認為不是本人語氣。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四項。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第四項。黑色海。悠真畫過。水瀨葵的遊戲帳號最後一張圖是黑色海。倒月。兩個都有。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第五項。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第五項。警方反應。悠真被當成自行離家。水瀨葵也被當成自行離家。兩個都被初期往自願方向處理。兩個的家屬都被擋在「自願離家」這個判定外面。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第六項。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第六項。研究資料。悠真的案件。我拿不到完整研究中心資料。水瀨葵的尋人頁也提到。學校和研究單位互推責任。家屬拿不到完整資料。兩邊都被擋。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著備忘錄上六條。六個共同點。她沒有打結論。她只是列。像在做查核報告。像在兼職的網路調查媒體整理資料來源。一條一條。不急著下判斷。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這些不是完整證據。每一條單獨拿出來都可以被解釋掉。年齡相似是巧合。睡眠檢查是普遍的學校合作項目。最後訊息不像本人是家屬主觀判斷。黑色海可以是網路模因。警方往自願離家處理是標準流程。研究資料不公開是個資保護。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但六條加在一起。兩個互不認識的孩子。做過同一項檢查。留過同一種圖像。失蹤後出現不像本人的訊息。都被當成自願離家。家屬都拿不到完整資料。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是巧合。不是模因。不是青春期。是同一件事。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把備忘錄關掉。不存。不截圖。備忘錄留在手機裡。沒有標題。沒有名字。只有六條字。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看了一眼時間。14:50。還有一個多小時。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯誰把家屬逼成這樣。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著螢幕上那個簡陋的尋人頁。白底。黑字。失蹤第 41 日。一條一條的更新。從「謝謝大家幫忙轉發」到「今天也沒有消息」。一條一條的留言回覆。每一條都說謝謝。不管對方說了什麼。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是陰謀組織。不是邪教。不是情報網。是一個母親。自己做了一個頁面。自己更新。自己回覆每一條留言。自己被罵。自己說謝謝。自己每天把數字加一。四十一日。四十二日。四十三日。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯是誰把她逼成這樣。是警察說這是自願離家。是學校說這是青春期。是研究單位說這是睡眠品質低下。是留言的人說孩子青春期離家不要怪社會。每一邊都有一個欄位。每一個欄位都裝不下她的孩子。所以她只能自己做頁面。自己等。自己把數字加一。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想起 no_moon 的話。大人會改口，圖不太會。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯對。大人會改口。警察會改報告。學校會改說法。研究單位會改數據。但那個母親的頁面不會改。每天的更新不會改。冰棒棍上的日期不會改。孩子畫的黑色海不會改。那些東西笨。那些東西土。那些東西沒有人覺得重要。正因為沒人覺得重要。它們才留得住。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把咖啡拿起來。喝了一口。涼了。苦的。她放下杯子。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯16:30。清澄區民中心。藍色傘。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯那個母親可能在那裡。或者認識那個母親的人在那裡。他們不是危險的人。他們是被危險嚇怕的人。他們用藍色傘。用暗號。用不問名字的規則。不是因為他們是組織。是因為他們被組織傷過。被警察記過名字。被記者寫過報導。被陌生人問過名字然後消失。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我要去。", background: Background.Chapter_10_Ch10_Act6_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著手機。14:55。還有一個半小時。她站起來。把杯子拿到櫃台。走出咖啡店。", background: Background.Chapter_10_Ch10_Act6_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外面的光還是灰的。但她的腳步比來的時候快了一點。不是急。是決定了。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不帶小鏡子。不告訴琴音。不告訴警方。手機保持開機。不開定位。掌機靜音。不搜敏感詞。把地點寫在紙上。夾在筆記裡。", background: Background.Chapter_10_Ch10_Act6_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她一邊走一邊在腦子裡列清單。像在查核報告前確認來源。一條一條。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯安全措施。基本的。不是因為我信他們。是因為我不能不去。水瀨葵的頁面不是幻覺。四十一日不是幻覺。那個母親的每一條更新不是幻覺。如果有人知道為什麼這些孩子都畫了黑色海。如果有人知道為什麼他們都沒有回來。他們就在那裡。在一個有自動販賣機和老人下棋的地方。等一個拿著悠真帳號的姐姐。", background: Background.Chapter_10_Ch10_Act6_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "15:10。她到家。開門。脫鞋。走到書桌前。把那張紙攤開。找到空白。寫。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯16:30。清澄區民中心。一樓公開休息區。藍色傘。一個字一個字。壓得很重。", background: Background.Chapter_10_Ch10_Act6_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙夾進私人筆記。私人筆記放進抽屜。用悠真的考試講義壓住。小鏡子在講義下面。她沒有碰它。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看了一眼房間。悠真的房間在走廊盡頭。門關著。她沒有進去。她不需要再進去。她已經知道門的那邊是什麼了。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不只是悠真的房間。不只是水瀨葵的鐵盒。不只是黑色海。是一片海。很多孩子都畫過。很多家屬都在等。很多頁面都在更新。很多數字都在變大。", background: Background.Chapter_10_Ch10_Act6_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我要去見他們。", background: Background.Chapter_10_Ch10_Act6_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "15:20。她從家裡出來。鎖門。鑰匙放進口袋。手機在口袋裡。掌機在包包裡。靜音。紙在內袋。私人筆記在抽屜裡。小鏡子在講義下面。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她開始走。往清澄區民中心的方向。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灰色的天。灰色的路。但她的腳步是穩的。不是因為不害怕。是因為害怕已經不再是最大的東西了。比害怕更大的。是一個母親寫了四十一日的「今天也沒有消息」。", background: Background.Chapter_10_Ch10_Act6_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想看完那五個字後面還有什麼。", background: Background.Chapter_10_Ch10_Act6_S2 },
];
